//go:build dev

package mcp

import (
	"context"
	"encoding/json"
	"sort"
	"strings"

	"github.com/Neaox/overcast/internal/capabilities"
)

// mergeCodeDerivedCoverage augments the coverage list with data from
// capabilities.AllCapabilities — the dev-only static snapshot generated by
// capgen. This replaces the regex-based heuristic used in non-dev builds.
func (p *RepoProvider) mergeCodeDerivedCoverage(existing []serviceCoverageEntry) []serviceCoverageEntry {
	// Build a map of service → []Capability from AllCapabilities.
	capsByService := make(map[string][]capabilities.Capability)
	for _, c := range capabilities.AllCapabilities {
		svc := strings.ToLower(c.Service)
		capsByService[svc] = append(capsByService[svc], c)
	}

	byService := make(map[string]serviceCoverageEntry, len(existing))
	for _, entry := range existing {
		byService[strings.ToLower(entry.Service)] = entry
	}

	for svc, caps := range capsByService {
		known := len(caps)
		implemented := 0
		for _, c := range caps {
			if c.Status >= capabilities.StatusSupported || c.Status == capabilities.StatusPartial {
				implemented++
			}
		}
		tier := inferTierFromCaps(caps)
		entry := serviceCoverageEntry{
			Service:        svc,
			Tier:           tier,
			Highlights:     "capability-registry derived",
			CoverageSource: "capabilities",
		}
		entry.KnownOps = &known
		entry.ImplementedOps = &implemented
		entry.Ops = &implemented

		if existingEntry, found := byService[svc]; found {
			existingEntry.KnownOps = entry.KnownOps
			existingEntry.ImplementedOps = entry.ImplementedOps
			existingEntry.CoverageSource = "status-md+capabilities"
			if existingEntry.Ops == nil {
				existingEntry.Ops = entry.ImplementedOps
			}
			byService[svc] = existingEntry
			continue
		}
		byService[svc] = entry
	}

	merged := make([]serviceCoverageEntry, 0, len(byService))
	for _, entry := range byService {
		merged = append(merged, entry)
	}
	sort.Slice(merged, func(i, j int) bool {
		return strings.ToLower(merged[i].Service) < strings.ToLower(merged[j].Service)
	})
	return merged
}

func (p *RepoProvider) codeDerivedCoverageForService(service string) (serviceCoverageEntry, bool) {
	service = strings.ToLower(strings.TrimSpace(service))
	if service == "" {
		return serviceCoverageEntry{}, false
	}
	var caps []capabilities.Capability
	for _, c := range capabilities.AllCapabilities {
		if strings.ToLower(c.Service) == service {
			caps = append(caps, c)
		}
	}
	if len(caps) == 0 {
		return serviceCoverageEntry{}, false
	}
	known := len(caps)
	implemented := 0
	for _, c := range caps {
		if c.Status >= capabilities.StatusSupported || c.Status == capabilities.StatusPartial {
			implemented++
		}
	}
	entry := serviceCoverageEntry{
		Service:        service,
		Tier:           inferTierFromCaps(caps),
		Highlights:     "capability-registry derived",
		CoverageSource: "capabilities",
	}
	entry.KnownOps = &known
	entry.ImplementedOps = &implemented
	entry.Ops = &implemented
	return entry, true
}

func inferTierFromCaps(caps []capabilities.Capability) string {
	implemented := 0
	for _, c := range caps {
		if c.Status >= capabilities.StatusSupported || c.Status == capabilities.StatusPartial {
			implemented++
		}
	}
	switch {
	case implemented >= 25:
		return "comprehensive"
	case implemented >= 8:
		return "core"
	default:
		return "minimal"
	}
}

// toolServiceCapabilities returns per-operation capability details for a service.
func (p *RepoProvider) toolServiceCapabilities(_ context.Context, params json.RawMessage) (any, error) {
	var args struct {
		Service string `json:"service"`
	}
	if len(params) > 0 {
		if err := json.Unmarshal(params, &args); err != nil {
			return nil, err
		}
	}
	if args.Service == "" {
		return nil, &jsonErr{code: -32602, msg: "service is required"}
	}
	svc := strings.ToLower(args.Service)
	type capEntry struct {
		Operation string `json:"operation"`
		Category  string `json:"category"`
		Status    string `json:"status"`
		Notes     string `json:"notes,omitempty"`
	}
	var ops []capEntry
	for _, c := range capabilities.AllCapabilities {
		if strings.ToLower(c.Service) == svc {
			ops = append(ops, capEntry{
				Operation: c.Operation,
				Category:  c.Category,
				Status:    c.Status.String(),
				Notes:     c.Notes,
			})
		}
	}
	if len(ops) == 0 {
		return nil, &jsonErr{code: -32602, msg: "no capabilities registered for service: " + args.Service}
	}
	return map[string]any{"service": svc, "count": len(ops), "operations": ops}, nil
}
